  Future<void> _uploadToS3() async {
    if (_selectedImage == null) return;
    
    setState(() {
      _uploadStatus = 'Uploading...';
    });

    try {
      final url = 'https://$bucketName.s3.$region.amazonaws.com/';
      final filename = Uuid().v4();
      final contentType = 'image/jpeg';
      
      final fileBytes = await _selectedImage!.readAsBytes();
      final contentLength = fileBytes.length;
      
      final date = DateTime.now().toUtc();
      final dateString = '${date.year}${date.month.toString().padLeft(2, '0')}${date.day.toString().padLeft(2, '0')}T${date.hour.toString().padLeft(2, '0')}${date.minute.toString().padLeft(2, '0')}${date.second.toString().padLeft(2, '0')}Z';
      
      final canonicalRequest = 'PUT\n'
          '/$filename\n'
          '\n'
          'host:$bucketName.s3.$region.amazonaws.com\n'
          'x-amz-date:$dateString\n'
          '\n'
          'host;x-amz-date\n'
          '${_hashHex(fileBytes)}';
      
      final stringToSign = 'AWS4-HMAC-SHA256\n'
          '$dateString\n'
          '${date.year}${date.month.toString().padLeft(2, '0')}${date.day.toString().padLeft(2, '0')}/$region/s3/aws4_request\n'
          '${_hashHex(canonicalRequest.codeUnits.join())}';
      
      final signingKey = _getSigningKey(awsSecretKey, date, region, 's3');
      final signature = _hexEncode(Hmac(sha256, signingKey).convert(stringToSign.codeUnits).bytes);
      
      final authorizationHeader = 'AWS4-HMAC-SHA256 '
          'Credential=$awsAccessKey/$dateString/$region/s3/aws4_request, '
          'SignedHeaders=host;x-amz-date, '
          'Signature=$signature';
      
      final response = await http.put(
        Uri.parse('$url$filename'),
        headers: {
          'Content-Type': contentType,
          'Content-Length': contentLength.toString(),
          'x-amz-date': dateString,
          'Authorization': authorizationHeader,
          'Host': '$bucketName.s3.$region.amazonaws.com',
        },
        body: fileBytes,
      );
      
      if (response.statusCode == 200) {
        setState(() {
          _uploadStatus = 'Upload successful!';
