          vision.Feature(type: 'FACE_DETECTION', maxResults: 5),
          vision.Feature(type: 'TEXT_DETECTION', maxResults: 5),
        ],
      ));
      
      final labels = response.responses[0].labelAnnotations;
      final faces = response.responses[0].faceAnnotations;
      final texts = response.responses[0].textAnnotations;
      
      final result = StringBuffer();
      
      if (labels != null && labels.isNotEmpty) {
        result.writeln('Labels:');
        for (var label in labels.take(3)) {
          result.writeln('- ${label.description}: ${label.score}');
        }
      }
      
      if (faces != null && faces.isNotEmpty) {
