  List<int> _getSigningKey(String key, DateTime date, String region, String service) {
    final kDate = Hmac(sha256, 'AWS4$key'.codeUnits).convert(date.toUtc().toString().substring(0, 8).codeUnits).bytes;
    final kRegion = Hmac(sha256, kDate).convert(region.codeUnits).bytes;
    final kService = Hmac(sha256, kRegion).convert(service.codeUnits).bytes;
    final kSigning = Hmac(sha256, kService).convert('aws4_request'.codeUnits).bytes;
    return kSigning;
  }

  String _hexEncode(List<int> bytes) {
    return bytes.map((b) => b.toRadixString(16).padLeft(2, '0')).join('');
  }

